const payload = $json.result ?? $json;
const source = payload?.data ?? {};
const tenantId = $('Estandarizar Variables').item.json.tenant_id || '';
const asText = (value) => typeof value === 'string' ? value.trim() : '';
const isUsefulText = (value) => {
  const normalized = asText(value);
  if (!normalized) return false;
  return !/no encontrada\.?$/i.test(normalized);
};
const info = source.info_liturgica && typeof source.info_liturgica === 'object' ? source.info_liturgica : {};
const readingDefinitions = [
  { key: 'primera_lectura', title: 'Primera lectura', variant: 'primera_lectura' },
  { key: 'salmo', title: 'Salmo de hoy', variant: 'salmo' },
  { key: 'segunda_lectura', title: 'Segunda lectura', variant: 'segunda_lectura' },
  { key: 'evangelio', title: 'Evangelio del día', variant: 'evangelio' },
  { key: 'reflexion', title: 'Reflexión del Evangelio de hoy', variant: 'reflexion' },
];
const readingCards = readingDefinitions
  .map((definition) => ({ ...definition, content: asText(source[definition.key]) }))
  .filter((definition) => isUsefulText(definition.content));
const response = readingCards.map((card) => card.content).join('\n\n').trim() || asText(payload?.result) || asText(payload?.message) || 'No pude obtener las lecturas del día.';
const previewBase = readingCards[0]?.content || asText(source.evangelio) || response;
const collapsedPreview = previewBase.length > 160 ? `${previewBase.substring(0, 160).trim()}... *(ver panel lateral)*` : previewBase;
const uiElements = readingCards.map((card) => ({
  type: 'reading_card',
  title: card.title,
  variant: card.variant,
  content: card.content,
}));
if (info && (info.dia || info.celebracion || info.color || info.tiempo_liturgico)) {
  uiElements.push({
    type: 'liturgical_info',
    title: 'Información litúrgica',
    day: info.dia || '',
    celebration: info.celebracion || '',
    color: info.color || '',
    liturgical_time: info.tiempo_liturgico || '',
  });
}
return {
  tenant_id: tenantId,
  response: response,
  texto: collapsedPreview,
  ui_elements: uiElements,
  source: 'mcp_catolico_lecturas',
};

// ── Analizador de Contenido v2 ──────────────────────────────────────────────
// Prioridad: ui_elements prearmados > PDF/QR URLs > tipos de archivo > longitud de texto
//
// NUEVOS TIPOS SOPORTADOS (Mozo Virtual):
//   pdf_url     → URL pública de download_report de Odoo — embeber en panel wide
//   payment_qr  → URL de QR de Mercado Pago — mostrar imagen QR en panel wide

const response = $input.item.json.response || '';
const tenantId = $input.item.json.tenant_id || '';
const presetUiElements = Array.isArray($input.item.json.ui_elements) ? $input.item.json.ui_elements : [];
const presetText = typeof $input.item.json.texto === 'string' ? $input.item.json.texto.trim() : '';

let uiElements = presetUiElements;
let texto = presetText || response;

if (!uiElements.length) {

  // ── 1. Detectar URL pública de carta/menú PDF de Odoo (docs_chatui o web/content con access_token)
  const pdfOdooMatch = response.match(
    /(https?:\/\/[^\s)"']+\/(?:docs_chatui\/[^\s)"']+\.pdf[^\s)"']*|web\/content\/\d+[^\s)"']*access_token=[^\s)"']+))/i
  );
  if (pdfOdooMatch) {
    const pdfUrl = pdfOdooMatch[1];
    uiElements = [{ type: 'pdf_url', title: 'Carta del Restaurante', url: pdfUrl }];
    texto = '¡Aquí está nuestra carta! Podés verla en el panel lateral 👉';
  }

  // ── 2. Detectar URL de imagen QR de Mercado Pago (report/barcode o qr_image_url)
  else if (
    response.match(/report\/barcode[^\s)"']*type=QR/i) ||
    response.match(/qr_image_url[^\s)"']*(https?:\/\/[^\s)"']+)/i)
  ) {
    const qrUrlMatch = response.match(/(https?:\/\/[^\s)"']+report\/barcode[^\s)"']*type=QR[^\s)"']*)/i)
      || response.match(/qr_image_url[":\s]+(https?:\/\/[^\s,)"']+)/i);
    const amountMatch = response.match(/\$?([\d,]+\.\d{2})/);
    const orderMatch = response.match(/\b(\d{6,})\b/);
    if (qrUrlMatch) {
      uiElements = [{
        type: 'payment_qr',
        title: 'Pago con Mercado Pago',
        qr_image_url: qrUrlMatch[1],
        amount: amountMatch ? parseFloat(amountMatch[1].replace(',', '')) : undefined,
        order_name: orderMatch ? orderMatch[1] : undefined,
      }];
      texto = response.replace(qrUrlMatch[0], '').trim().substring(0, 200) || '¡Escaneá el QR para pagar con Mercado Pago! 📱';
    }
  }

  // ── 3. Detectar archivo PDF local
  else {
    const pdfMatch = response.match(/([/\w\-\.]+\.pdf[\w\-\.]*)/i);
    if (pdfMatch) {
      const filePath = pdfMatch[1];
      const name = filePath.split('/').pop().replace(/\.pdf.*/i, '');
      uiElements = [{ type: 'pdf', name: name, path: filePath }];
      texto = response.replace(pdfMatch[0], '').trim();
      if (!texto || texto.length < 40) texto = `**${name}** *(ver panel lateral)*`;
    }

    // ── 4. Contenido largo → sidebar
    else if (response.length > 300) {
      const mdMatch = response.match(/([\w/\-\.]+\.md[\w\-\.]*)/i);
      const htmlMatch = response.match(/([\w/\-\.]+\.html[\w\-\.]*)/i);
      let title = 'Respuesta';
      if (mdMatch) {
        title = mdMatch[1].split('/').pop().replace(/\.md.*/i, '');
      } else if (htmlMatch) {
        title = htmlMatch[1].split('/').pop().replace(/\.html.*/i, '');
      }
      uiElements = [{ type: 'sidebar', title: title, content: response }];
      // Preview inteligente: cortar en el último salto de línea antes del límite
      const limit = 200;
      let preview = response.substring(0, limit);
      const lastNewline = preview.lastIndexOf('\n');
      if (lastNewline > 80) preview = preview.substring(0, lastNewline);
      texto = preview.replace(/[#*`]/g, '').trim() + '... *(ver panel lateral)*';
    }

    // ── 5. Imagen
    else {
      const imgMatch = response.match(/(https?:\/\/[^\s]+\.(?:jpg|jpeg|png|webp|gif))/i);
      if (imgMatch) {
        uiElements = [{ type: 'image', name: 'Imagen', url: imgMatch[1] }];
      }
    }
  }

} else if (!texto) {
  // Hay ui_elements pero no texto: generar preview
  const first = uiElements[0];
  texto = first?.title || first?.name || 'Respuesta disponible en el panel lateral';
  if (texto.length > 200) texto = texto.substring(0, 200) + '...';
}

return {
  tenant_id: tenantId,
  response: response,
  texto: texto,
  ui_elements: uiElements,
  actions: $input.item.json.actions || [],
};

const data = $json;
const tenantId = $('Estandarizar Variables').item.json.tenant_id || 'catolico';
const content = data?.choices?.[0]?.message?.content
  || data?.content
  || data?.result
  || data?.message
  || 'Sin respuesta del asistente.';
return {
  tenant_id: tenantId,
  response: content,
  texto: content.length > 160 ? content.substring(0, 160) + '... *(ver panel lateral)*' : content,
  ui_elements: []
};

// ── Normalizar Hermes Resto v2 ───────────────────────────────────────────────
// Extrae la respuesta de Hermes y detecta URLs especiales para construir
// ui_elements correctos ANTES de llegar al Analizador de Contenido.
//
// Tipos detectados:
//   pdf_url    → URL pública de download_report (docs_chatui/ o web/content/?access_token=)
//   payment_qr → URL de imagen QR de Mercado Pago (report/barcode/?type=QR)

const data = $json;
const tenantId = $('Estandarizar Variables').item.json.tenant_id || 'resto';
const content = data?.choices?.[0]?.message?.content
  || data?.content
  || data?.result
  || data?.message
  || 'Sin respuesta del asistente.';

let uiElements = [];
let texto = content;

// ── 1. Detectar URL pública PDF del menú (docs_chatui o web/content con access_token)
const pdfOdooMatch = content.match(
  /(https?:\/\/[^\s)"'\]]+\/(?:docs_chatui\/[^\s)"'\]]+\.pdf[^\s)"'\]]*|web\/content\/\d+[^\s)"'\]]*access_token=[^\s)"'\]]+))/i
);
if (pdfOdooMatch) {
  const pdfUrl = pdfOdooMatch[1];
  uiElements = [{ type: 'pdf_url', title: 'Carta del Restaurante', url: pdfUrl }];
  // Texto: usar lo que dijo Hermes antes del link, o mensaje genérico
  const beforeLink = content.substring(0, content.indexOf(pdfOdooMatch[0])).trim();
  texto = (beforeLink && beforeLink.length > 10)
    ? beforeLink + ' 👉'
    : '¡Aquí está nuestra carta! Podés verla en el panel lateral 👉';
}

// ── 2. Detectar URL de imagen QR de Mercado Pago
else {
  const qrUrlMatch = content.match(
    /(https?:\/\/[^\s)"'\]]+\/report\/barcode\/[^\s)"'\]]*type=QR[^\s)"'\]]*)/i
  ) || content.match(
    /qr_image_url[":\s]+(https?:\/\/[^\s,)"'\]]+)/i
  );

  if (qrUrlMatch) {
    const qrImgUrl = qrUrlMatch[1] || qrUrlMatch[0];
    // Extraer monto si viene en la respuesta (ej: $ 39.81 o ARS 39.81)
    const amountMatch = content.match(/(?:ARS|\$)\s*([\d.,]+)/);
    // Extraer número de orden (6+ dígitos o formato 000XXX)
    const orderMatch = content.match(/\b(0{2,}\d{3,}|\d{6,})\b/);
    uiElements = [{
      type: 'payment_qr',
      title: 'Pago con Mercado Pago',
      qr_image_url: qrImgUrl,
      amount: amountMatch ? parseFloat(amountMatch[1].replace(',', '.')) : undefined,
      order_name: orderMatch ? orderMatch[1] : undefined,
    }];
    // Texto: lo que dijo Hermes (sin la URL del QR)
    texto = content.replace(qrImgUrl, '').trim();
    if (!texto || texto.length < 10) texto = '¡Escaneá el QR para pagar con Mercado Pago! 📱';
  }
}

// ── Preview de texto para el chat (si no hay ui_elements especiales)
if (!uiElements.length) {
  // Preview inteligente: cortar en el último salto de línea antes del límite
  const limit = 200;
  if (texto.length > limit) {
    let preview = texto.substring(0, limit);
    const lastNewline = preview.lastIndexOf('\n');
    if (lastNewline > 80) preview = preview.substring(0, lastNewline);
    texto = preview.trim() + '... *(ver panel lateral)*';
  }
}

return {
  tenant_id: tenantId,
  response: content,
  texto: texto,
  ui_elements: uiElements,
};

const data = $json;
const tenantId = $('Estandarizar Variables').item.json.tenant_id || 'default';
const content = data?.choices?.[0]?.message?.content
  || data?.content
  || data?.result
  || data?.message
  || 'Sin respuesta del asistente.';
return {
  tenant_id: tenantId,
  response: content,
  texto: content.length > 160 ? content.substring(0, 160) + '... *(ver panel lateral)*' : content,
  ui_elements: []
};

// Extraer nombre del documento buscado del mensaje original
const message = $('Estandarizar Variables').item.json.message || '';
const msgNorm = message.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

// Detectar qué quiso resumir el usuario (texto después de resumir/sintetizar/síntesis)
const resumeMatch = msgNorm.match(/\b(?:resum[a-z]*|sintetiz[a-z]*|sintesis)\s+(?:(?:el|la|los|las|del?|un|una)\s+(?:documento\s+)?)?(.+?)(?:\s+(?:por\s+favor|porfavor)|\s*[.?!]*\s*$)/i);
const docQuery = resumeMatch ? resumeMatch[1].trim() : msgNorm;

// Leer la lista de documentos del nodo anterior
const raw = $json;
let result = raw;

// Parsear respuesta MCP (puede venir envuelta en content[])
if (Array.isArray(raw.content) && raw.content.length > 0) {
  const textEntry = raw.content.find(e => e && e.type === 'text');
  if (textEntry && textEntry.text) {
    try { result = JSON.parse(textEntry.text); } catch(e) {}
  }
} else if (raw.result) {
  result = raw.result;
}
if (result && result.content && Array.isArray(result.content)) {
  const inner = result.content.find(e => e && e.type === 'text');
  if (inner && inner.text) {
    try { result = JSON.parse(inner.text); } catch(e) {}
  }
}

const documentos = (result && Array.isArray(result.documentos)) ? result.documentos
  : (result && result.data && Array.isArray(result.data.documentos)) ? result.data.documentos
  : [];

// Función de similitud Jaccard sobre palabras
function tokenize(str) {
  return str.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .split(/\W+/).filter(w => w.length > 2);
}
function jaccard(tokA, tokB) {
  const setA = new Set(tokA);
  const setB = new Set(tokB);
  const inter = [...setA].filter(x => setB.has(x)).length;
  const union = new Set([...setA, ...setB]).size;
  return union === 0 ? 0 : inter / union;
}

const queryTokens = tokenize(docQuery);
const queryNorm = docQuery.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const scored = documentos.map(doc => {
  const title = String(doc.titulo || doc.title || doc.nombre || '');
  const titleNorm = title.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const titleTokens = tokenize(titleNorm);
  const jaccardScore = jaccard(queryTokens, titleTokens);
  const containsScore = titleNorm.includes(queryNorm) ? 1 : queryNorm.split(' ').filter(w => w.length > 2 && titleNorm.includes(w)).length / Math.max(queryNorm.split(' ').length, 1);
  return { titulo: title, score: jaccardScore * 0.6 + containsScore * 0.4 };
}).sort((a, b) => b.score - a.score);

const best = scored[0];
const top4 = scored.slice(0, 4).map(s => s.titulo);
const tenantId = $('Estandarizar Variables').item.json.tenant_id || 'catolico';

return {
  tenant_id: tenantId,
  titulo_buscado: docQuery,
  titulo_encontrado: best ? best.titulo : null,
  coincidencia_exacta: best ? best.score > 0.5 : false,
  top4_similares: top4,
  message: $('Estandarizar Variables').item.json.message || '',
};

const raw = $json;
let result = raw;

// Parsear respuesta MCP
if (Array.isArray(raw.content) && raw.content.length > 0) {
  const textEntry = raw.content.find(e => e && e.type === 'text');
  if (textEntry && textEntry.text) {
    try { result = JSON.parse(textEntry.text); } catch(e) {}
  }
} else if (raw.result) {
  result = typeof raw.result === 'string' ? (() => { try { return JSON.parse(raw.result); } catch(e) { return { content: raw.result }; } })() : raw.result;
}
if (result && result.content && Array.isArray(result.content)) {
  const inner = result.content.find(e => e && e.type === 'text');
  if (inner && inner.text) {
    try { result = JSON.parse(inner.text); } catch(e) {}
  }
}

const validacion = $('Validar Titulo Resumir').item.json;
const tenantId = validacion.tenant_id || 'catolico';
const content = (result && (result.content || result.contenido || result.texto || result.summary || '')).toString().trim()
  || (raw.content || '').toString().trim();
const titulo = (result && result.titulo) || validacion.titulo_encontrado || validacion.titulo_buscado || 'Documento';

if (!content || content.length < 20) {
  const errMsg = (result && result.error) || 'No pude generar el resumen del documento.';
  return [{json:{
    tenant_id: tenantId,
    texto: '❌ ' + errMsg,
    response: errMsg,
    ui_elements: [],
    source: 'mcp_catolico_resumir'
  }}];
}

// Construir advertencia si no hubo coincidencia exacta
let advertencia = '';
if (!validacion.coincidencia_exacta) {
  const top4List = (validacion.top4_similares || []).map(t => `  • ${t}`).join('\n');
  advertencia = `\n\n---\n⚠️ **Nota:** Pediste resumir _"${validacion.titulo_buscado}"_ pero no encontré ese título exacto en el catálogo. Se resumió el documento más similar: **"${titulo}"**.\n\n📋 Los 4 títulos más similares disponibles son:\n${top4List}`;
}

const previewSuffix = validacion.coincidencia_exacta ? '' : ' _(documento más similar)_';
const preview = `📄 Resumen de **"${titulo}"**${previewSuffix} listo en el panel lateral 👉`;
const uiElements = [{ type: 'sidebar', title: titulo, content: content + advertencia }];

return [{ json: {
  tenant_id: tenantId,
  texto: preview,
  response: content,
  ui_elements: uiElements,
  source: 'mcp_catolico_resumir'
}}];

const payload = $json.result ?? $json;
const source = payload?.data ?? payload ?? {};
const tenantId = $("Estandarizar Variables").item.json.tenant_id || "";
const originalMsg = $("Estandarizar Variables").item.json.message || "";
const asText = (v) => typeof v === "string" ? v.trim() : "";
const content = asText(source.content) || asText(source.contenido) || asText(source.texto) || asText(payload?.content) || asText(payload?.result) || asText(payload?.message) || "";
const msgMatch = originalMsg.match(/obtener\\s+documento\\s+(.+)/i);
const title = asText(source.titulo) || asText(source.nombre) || (msgMatch ? msgMatch[1].trim() : "") || asText(source.filename) || "Documento";

if (!content) {
  return { tenant_id: tenantId, texto: "No pude obtener el documento solicitado.", response: "", ui_elements: [], source: "mcp_catolico_leer_documento" };
}

const preview = title + " — documento cargado en el panel lateral 👉";
const uiElements = [{ type: "sidebar", title: title, content: content }];

return { tenant_id: tenantId, texto: preview, response: content, ui_elements: uiElements, source: "mcp_catolico_leer_documento" };
